#include<bits/stdc++.h>
using namespace std;
const int MAXN=5e+5;
int n,a[MAXN],b[MAXN],c[MAXN],x,y,z,A[MAXN],B[MAXN],C[MAXN];
int main(void){
	//freopen("medal.in","r",stdin);
	//freopen("medal.out","w",stdout);
	scanf("%d",&n);
	for(int i=1;i<=n;++i)scanf("%d%d%d",a+i,b+i,c+i),A[i]=a[i],B[i]=b[i],C[i]=c[i];
	sort(a+1,a+n+1);
	sort(b+1,b+n+1);
	sort(c+1,c+n+1);
	for(int i=1;i<=n;++i){
		x=upper_bound(a+1,a+n+1,A[i])-a-1;
		y=upper_bound(b+1,b+n+1,B[i])-b-1;
		z=upper_bound(c+1,c+n+1,C[i])-c-1;
		printf("%d\n",n+1-max(max(x,y),z));
	}
	return false;
}
